import os
import base64

def create_project():
    app_name = "Trustrium Mining"
    
    # Store files as base64 to avoid string escaping issues
    project_files = {
        "build.gradle": "",
        "settings.gradle": "cm9vdFByb2plY3QubmFtZSA9ICJUcnVzdHJpdW0gTWluaW5nIgppbmNsdWRlICc6YXBwJw==",
        "gradle/wrapper/gradle-wrapper.properties": "",
        "app/src/main/AndroidManifest.xml": "",
        "app/src/main/res/drawable/ic_launcher.xml": "",
        "app/src/main/java/com/example/trustriummining/MainActivity.kt": "",
        "app/src/main/java/com/example/trustriummining/SplashScreenActivity.kt": "",
        "app/src/main/res/layout/activity_main.xml": "",
        "app/src/main/res/drawable/custom_progress_bar.xml": "",
        "app/src/main/res/values/colors.xml": "",
        "app/build.gradle": "",
        "app/proguard-rules.pro": "",
        ".github/workflows/build_apk.yml": "",
        "README.md": ""
    }
    
    base_dir = f"./{app_name.replace(' ', '_')}_Android"
    
    print(f"🚀 Initializing {app_name} Android Project...")
    
    for path, b64_content in project_files.items():
        full_path = os.path.join(base_dir, path)
        os.makedirs(os.path.dirname(full_path), exist_ok=True)
        
        # Decode base64
        file_content = base64.b64decode(b64_content).decode('utf-8')
        
        with open(full_path, "w", encoding="utf-8") as f:
            f.write(file_content)
        print(f"  [CREATED] {path}")
        
    print("\n✅ Project structure ready at: " + os.path.abspath(base_dir))
    print("--------------------------------------------------")
    print("Next Steps:")
    print("1. Upload this folder to a new GitHub repository.")
    print("2. The included GitHub Actions will build your APK automatically.")
    print("3. Alternatively, open in Android Studio for local development.")

if __name__ == "__main__":
    create_project()
